for (const item of $input.all()) {
  let raw = item.json.text || item.json.data || "";

  // Remove non-printable/control Unicode characters (\u0000-\u001F, \u007F)
  raw = raw.replace(/[\x00-\x1F\x7F]+/g, " ");

  // Collapse spaces, tabs, newlines
  const clean = raw
    .replace(/\s+/g, " ")
    .replace(/[,]+/g, ",")  // clean extra commas if any
    .trim();

  // Preview (first 3000 chars)
  const preview = clean.toLowerCase().substring(0, 3000);

  // Escape for JSON safely
  const escapedPreview = preview
    .replace(/\\/g, "\\\\")   // escape backslashes
    .replace(/"/g, '\\"')     // escape quotes
    .replace(/\r?\n/g, "\\n"); // escape newlines

  // Store back in item
  item.json.preview = escapedPreview;
  item.json.text = clean;
  item.json.document_hint = {}; // placeholder

}

return $input.all();

